mapper.select:
select c.id as course_id,
       case when occ.course_id is null then 0 else 1 end as collection_flag,
       case when ocb.course_id is null then 0 else 1 end as buy_flag
from osh_course c
left join (
    select distinct course_id
    from osh_course_collection
    where user_id = #{userId}
      and delete_flag = 0
      and course_id in

          #{courseId}

) occ on occ.course_id = c.id
left join (
    select distinct course_id
    from osh_course_buy
    where user_id = #{userId}
      and delete_flag = 0
      and pay_status = 'paid'
      and course_id in

          #{courseId}

) ocb on ocb.course_id = c.id
where c.id in

    #{courseId}
